DASHBOARD_PAGE = "import { createClient } from \"@/lib/supabase/server\";\nimport SignOutButton from \"./sign-out-button\";\n\nexport default async function DashboardPage() {\n  const supabase = await createClient();\n  const {\n    data: { user },\n  } = await supabase.auth.getUser();\n\n  const displayName =\n    (user?.user_metadata?.display_name as string | undefined) ||\n    (user?.user_metadata?.full_name as string | undefined) ||\n    user?.email;\n\n  return (\n    <div className=\"min-h-screen bg-brand-gray\">\n      <header className=\"relative z-10 flex items-center justify-between bg-brand-maroon px-6 py-4 shadow-[0_4px_12px_rgba(0,0,0,0.25)]\">\n        <div className=\"flex items-center gap-3\">\n          <div className=\"flex h-8 w-8 items-center justify-center rounded-md bg-white p-1\">\n            <img\n              src=\"/logo.png\"\n              alt=\"Hendrickson\"\n              className=\"h-full w-full object-contain\"\n            />\n          </div>\n          <span className=\"text-lg font-bold text-white\">Hendrickson</span>\n        </div>\n        <div className=\"flex items-center gap-4\">\n          <span className=\"text-sm text-white/70\">{displayName}</span>\n          <SignOutButton />\n        </div>\n      </header>\n\n      <main className=\"p-8\">\n        <h1 className=\"text-2xl font-bold text-black\">Dashboard</h1>\n        <p className=\"mt-1 text-black/60\">Welcome back, {displayName}</p>\n      </main>\n    </div>\n  );\n}\n"

with open("app/dashboard/page.tsx", "w") as f:
    f.write(DASHBOARD_PAGE)
print("Added header shadow")
